con:mockOperation.con:dispatchPath:
import com.eviware.soapui.support.XmlHolder
import com.eviware.soapui.impl.wsdl.support.wsdl.WsdlContext
import com.eviware.soapui.impl.wsdl.support.wsdl.WsdlValidator
import com.eviware.soapui.impl.wsdl.panels.mockoperation.WsdlMockRequestMessageExchange

//Läs in mockens data.xml
import se.skl.rivta.tksupport.soapui.datasource.XmlDataReaderMock
import com.eviware.soapui.support.GroovyUtils
def utils = new GroovyUtils(context)
def dataFile = new File(utils.projectPath + "/mockdata.xml")
def source = new XmlDataReaderMock(context, dataFile)
source.load()

mh = new se.skl.rivta.tksupport.soapui.MockHelper(mockRequest, mockOperation)
context.validationMessages = mh.getSchemaErrorsInRequest() ?: mh.getSchematronErrorsInRequest("constraints.xml") ?: mh.getEmptyElementsInRequest() ?: null
if (context.validationMessages) {
	return "SoapFault"
}

def holder = new XmlHolder( mockRequest.requestContent )
holder.namespaces['soapenv'] = 'http://schemas.xmlsoap.org/soap/envelope/'
holder.namespaces['urn'] = 'urn:riv:itintegration:registry:1'
holder.namespaces['urn1'] = 'urn:riv:itintegration:engagementindex:FindContentResponder:1'

def registeredResidentIdentification = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:FindContent/urn1:registeredResidentIdentification')
def serviceDomain = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:FindContent/urn1:serviceDomain')
def categorization = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:FindContent/urn1:categorization')
def logicalAddress = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:FindContent/urn1:logicalAddress')
def sourceSystem = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:FindContent/urn1:sourceSystem')

def now = new Date()
context.registeredResidentIdentification = registeredResidentIdentification
context.serviceDomain = serviceDomain
context.categorization = categorization ?: "caa-ga"
context.logicalAddress = logicalAddress ?: "NMT0000001-LOGI"
context.mostRecentContent = (now - 15).format("yyyyMMddHHmmss")
context.sourceSystem = sourceSystem ?: "NMT0000001-LOGI"
context.creationTime = (now - 20).format("yyyyMMddHHmmss")
context.updateTime = (now - 10).format("yyyyMMddHHmmss")
context.dataController = "NMT0000001-DATA"

if (mockRequest.requestHeaders['x-mock-response'] != null){
	log.info(mockRequest.requestHeaders['x-mock-response'][0])
	return mockRequest.requestHeaders['x-mock-response'][0]
}
else{
	return mockOperation.getMockResponseByName(context.response) ? context.response : "Basic Response"
}
